ExtractDataFromBMP[bmpFile_] :=
  Module[{imageData, startIndex, endIndex, extractedData, outputString},
    imageData = BinaryReadList[bmpFile];
    If[imageData == {}, Return[$Failed]];
    startIndex = 55;
    endIndex = Length[imageData] - 15; (* Предотвращение выхода за пределы списка *)
    extractedData = Reap[
      While[startIndex <= endIndex &&
        imageData[[startIndex ;; Min[startIndex + 15, endIndex]]] =!= 
        ConstantArray[0, 16],
        Sow[imageData[[startIndex]]];
        startIndex++;
      ]
    ][[2, 1]]; (* Получаем список извлеченных элементов *)
